// Build-time bundler for the foliate-js WebView reader.
//
// foliate-js is multi-file native-ESM with heavy dynamic imports and a vendored
// zip/inflate lib (`vendor/zip.js`, `vendor/fflate.js`). React Native's Metro
// bundler can't ship that to a WebView document, and the WebView must read
// MOBI/AZW3 OFFLINE (from a downloaded file) — so we cannot rely on loading
// foliate's modules from the app server at runtime.
//
// This step uses esbuild (pinned exactly — see apps/mobile/package.json — so
// the emitted bytes are reproducible) to inline ALL of foliate-js — including
// every `await import('./…')` and the vendored libs — into ONE self-contained
// browser IIFE. The IIFE imports `view.js`, which registers the `<foliate-view>`
// custom element as a side effect. The result is emitted as a TS module
// exporting the JS source as a string (`FOLIATE_BUNDLE_JS`), so Metro bundles it
// like any other source file and `MobiWebView` can embed it in the WebView's
// HTML — fully offline-capable, no asset-loading / file-URI plumbing.
//
// Regeneration is MANUAL: `pnpm -F @bookkeeprr/mobile build:foliate`. The
// generated file IS committed and is the source of truth — a fresh checkout
// (and CI) builds without running this step. There is no automatic drift guard;
// re-run this script whenever the `foliate-js` dependency is bumped.

import { build } from 'esbuild';
import { createRequire } from 'node:module';
import { writeFile, mkdir } from 'node:fs/promises';
import { resolve, dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const appRoot = resolve(__dirname, '..');
const outFile = join(appRoot, 'src/features/reader/generated/foliate-bundle.ts');

async function main() {
  // Resolve foliate-js's view.js to an absolute path so esbuild can bundle it
  // regardless of where the temp entry would live. Importing view.js
  // `customElements.define`s `<foliate-view>` as a side effect; esbuild inlines
  // every `await import('./…')` and the vendored zip/fflate libs from there.
  const require = createRequire(join(appRoot, 'package.json'));
  const viewEntry = require.resolve('foliate-js/view.js');

  const result = await build({
    entryPoints: [viewEntry],
    bundle: true,
    format: 'iife',
    platform: 'browser',
    target: ['es2020'],
    // Inline dynamic imports so the WebView document is fully self-contained.
    write: false,
    minify: true,
    legalComments: 'none',
    // Resolve foliate-js from the workspace store.
    absWorkingDir: appRoot,
    logLevel: 'warning',
  });

  const js = result.outputFiles[0].text;

  // Embed the bundle as a backtick template literal. Escape backslashes,
  // backticks, and `${` so the string survives verbatim into the TS source.
  const escaped = js
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');

  const banner = `// AUTO-GENERATED by scripts/build-foliate-bundle.mjs — DO NOT EDIT.
//
// A self-contained browser IIFE bundle of foliate-js (view.js + all dynamic
// imports + the vendored zip/fflate libs), inlined by esbuild. Importing this
// JS inside the MobiWebView document registers the \`<foliate-view>\` custom
// element. Regenerate with \`pnpm -F @bookkeeprr/mobile build:foliate\`.
/* eslint-disable */
`;

  await mkdir(dirname(outFile), { recursive: true });
  await writeFile(outFile, `${banner}\nexport const FOLIATE_BUNDLE_JS = \`${escaped}\`;\n`, 'utf8');

  console.log(`[build-foliate-bundle] wrote ${outFile} (${js.length} bytes of JS)`);
}

main().catch((err) => {
  console.error('[build-foliate-bundle] failed:', err);
  process.exit(1);
});
